public class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
}

public boolean isInsufficient(TreeNode node, int limit, int sum) {
    if (node == null) {
        return true;
    }

    sum += node.val;
    if (node.left == null && node.right == null) {
        return sum < limit;
    }

    boolean leftInsufficient = isInsufficient(node.left, limit, sum);
    boolean rightInsufficient = isInsufficient(node.right, limit, sum);

    if (leftInsufficient) {
        node.left = null;
    }
    if (rightInsufficient) {
        node.right = null;
    }

    return leftInsufficient && rightInsufficient;
}

public TreeNode sufficientSubset(TreeNode root, int limit) {
    if (isInsufficient(root, limit, 0)) {
        return null;
    }
    return root;
}
